// // This module implements a 8-bit down counter that decrements its value on each clock cycle and resets to zero when a reset signal is high.
module up_counter(
    input clk,
    input rst,
    output reg [7:0] count
);

always @(posedge clk or posedge rst) begin
    if (rst)
        count <= 8'b0;
    else
        count <= count + 1;
end

endmodule
